def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        base_score = 0
        weights = [0.9, 1.3, 0.7, 1.5, 1.1]
        for layer in range(5):
            layer_score = 0
            for power in range(1, 20):
                factor = weights[layer] * ((-1)**(power + layer)) * (1 / (power**(1.5 + 0.1 * layer)))
                term = factor * (ratio ** power)
                layer_score += term
            base_score += max(0, layer_score)
        leftover = capacity - item
        multiplier = 1
        if leftover < 0.02 * capacity:
            multiplier = 3.0
        elif leftover < 0.05 * capacity:
            multiplier = 2.0
        elif leftover < 0.15 * capacity:
            multiplier = 1.3
        else:
            multiplier = 0.8
        base_score *= multiplier
        mods = {3: int(capacity) % 3 == 0, 5: int(capacity) % 5 == 0, 7: int(capacity) % 7 == 0, 11: int(capacity) % 11 == 0}
        penalty = 0
        if mods[3] and mods[5] and mods[7]:
            penalty -= 0.3 * (capacity / 12)
        elif mods[3] and mods[5]:
            penalty -= 0.18 * (capacity / 10)
        elif mods[5] and mods[7]:
            penalty -= 0.22 * (capacity / 14)
        elif mods[3] and mods[7]:
            penalty -= 0.15 * (capacity / 18)
        elif mods[11]:
            penalty -= 0.2 * (capacity / 25)
        elif mods[7]:
            penalty -= 0.1 * (capacity / 20)
        elif mods[5]:
            penalty -= 0.12 * (capacity / 22)
        elif mods[3]:
            penalty -= 0.08 * (capacity / 16)
        else:
            penalty -= 0.04 * (capacity / 30)
        base_score += penalty
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * (1 + 0.5*(k%2))
            if diff < threshold:
                base_score += 0.3 * k
            elif diff < 3 * threshold:
                base_score -= 0.1 * k
            else:
                base_score -= 0.15 * k
        for p in range(1, 4):
            segment = capacity / p
            variation = abs(segment - item)
            bound = 0.025 * segment
            if variation < bound:
                base_score *= (1.1 + 0.07 * p)
            elif variation < 1.5 * bound:
                base_score *= (1 + 0.03 * p)
        if base_score < 0:
            base_score = 0
        if base_score > 3:
            factor = 1 + 0.02 * np.log1p(base_score)
            base_score *= factor
        priorities[i] = base_score
    return priorities
